+import { ctx, images } from '../canvas';
+
+/*
+ Tile-based floor rendering for rooms.
+ Each tile is 16x16 px.
+ Tile types: stone, wood, carpet, cobblestone
+ Each type has 4 variants (numbered 0-3).
+ Room types map to floor tile types:
+   - dungeon: stone
+   - house: wood
+   - throne: carpet
+   - village: cobblestone
+ If room type unknown, fallback to stone.
+*/
+
+const TILE_SIZE = 16;
+
+// Tile image assets are assumed loaded and available in images.floorTiles
+// Structure: images.floorTiles[type][variant] = Image object
+// e.g. images.floorTiles.stone[0], images.floorTiles.wood[2], etc.
+
+const floorTileTypes = ['stone', 'wood', 'carpet', 'cobblestone'];
+
+const roomFloorTypeMap = {
+  dungeon: 'stone',
+  house: 'wood',
+  throne: 'carpet',
+  village: 'cobblestone',
+};
+
+function getFloorTypeForRoom(room) {
+  return roomFloorTypeMap[room.type] || 'stone';
+}
+
+// Simple pseudo-random variation based on tile coords for variation
+function getTileVariant(x, y) {
+  // deterministic variation 0-3
+  return (x * 3 + y * 7) % 4;
+}
+
+export function renderRoom(room) {
+  const floorType = getFloorTypeForRoom(room);
+  const tiles = images.floorTiles[floorType];
+  if (!tiles) {
+    // fallback to flat fill if no tiles loaded
+    ctx.fillStyle = room.floorColor || '#888';
+    ctx.fillRect(room.x, room.y, room.width, room.height);
+    return;
+  }
+
+  const startX = room.x;
+  const startY = room.y;
+  const endX = room.x + room.width;
+  const endY = room.y + room.height;
+
+  // Draw floor tiles in a grid covering the room area
+  for (let y = startY; y < endY; y += TILE_SIZE) {
+    for (let x = startX; x < endX; x += TILE_SIZE) {
+      const variant = getTileVariant((x - startX) / TILE_SIZE, (y - startY) / TILE_SIZE);
+      const tileImg = tiles[variant];
+      if (tileImg) {
+        ctx.drawImage(tileImg, x, y, TILE_SIZE, TILE_SIZE);
+      } else {
+        // fallback fill if tile missing
+        ctx.fillStyle = '#444';
+        ctx.fillRect(x, y, TILE_SIZE, TILE_SIZE);
+      }
+    }
+  }
+}
+
+// Heartbeat to indicate progress (if needed)
+// emitHeartbeat('renderRoom floor tiles applied');
