+// Load floor tile images
+function loadFloorTileImages() {
+  const types = ['stone', 'wood', 'carpet', 'cobblestone'];
+  types.forEach(type => {
+    for (let i = 0; i < 4; i++) {
+      const img = new Image();
+      img.src = `assets/floortiles/${type}_${i}.png`;
+      images.floorTiles[type][i] = img;
+    }
+  });
+}
